    "status": "not_fulfilled",
    "notes": "意图识别未满足核心期望：意图标签错误导致业务意图丢失，置信度过低进一步削弱可用性。"
  },
  "intent_model": {
    "primary_intent": "客户特征分析/客群洞察",
    "secondary_intents": ["客户画像", "重疾险客户分析"],
    "confidence_expected": "high",
    "slots_required": ["time_period（上季度）", "product（重疾险）", "analysis_type（客户特征）"]
  },
  "consumer_contract": {
    "expected_output_format": "intent_label, confidence, slots",
    "critical_dimensions": ["intent_label", "confidence_threshold"]
  },
  "reconstructed_intent": "用户希望查看上季度购买了重疾险的客户群体的特征画像，属于营销规划场景下的客户分析/客群洞察意图。",
  "judge_basis": "基于用户输入文本和通用营销领域知识，该查询明显指向客户画像分析，不应被归类为“其他意图”。同时，低置信度进一步表明识别结果不可靠。",
  "judge_method": "结合语义理解、意图分类常识及系统输出的客观数据，比照预期业务逻辑进行定性判断。",
  "semantic_equivalence_checks": [],
  "reference_generation_basis": {
    "method": "无外部参考意图，完全基于用户输入和项目上下文推导期望意图",
    "input_considered": "用户原始查询：“帮我看看上季度买了重疾险的客户都是啥样的？”"
  },
  "verdict_derivation": {
    "source": "从业务期望评估结果推导",
    "details": "两项评估均未通过（意图标签错误、置信度不达标），因此整体判定为未满足。"
  },
  "boundary_decision": {
    "within_evaluable_scope": true,
    "evaluable_errors": [],
    "uncontrollable_limits": []
  },
  "evaluation_boundary": {
    "scope": "single_turn_intent_recognition",
    "excludes": ["multi_turn_planning", "sse_card_generation"],
    "note": "仅评估单轮查询的意图标签和基础可信度，不涉及规划卡片生成或多轮对话状态。"
  },
  "missing": [],
  "wrong": [
    {
      "element": "intent_label",
      "expected": "客户分析/客群洞察（或其他具体营销分析标签）",
      "actual": "other（其他意图）",
      "reason": "用户意图为获取重疾险客户特征，与“其他意图”明显不匹配。"
    },
    {
      "element": "confidence",
      "expected": "> 0.7",
      "actual": "0.5",
      "reason": "查询语义清晰，模型应具备更高置信度。"
    }
  ],
  "extra": [],
  "evidence": [
    {
      "source": "run_trace.raw_response",
      "content": "intent_name=“其他意图”, confidence=0.5"
    },
    {
      "source": "user_input",
      "content": "“帮我看看上季度买了重疾险的客户都是啥样的？”"
    }
  ],
  "reasoning_summary": "用户查询明确表达了分析重疾险客户特征的需求，属于典型的营销客户洞察意图。然而，系统返回了兜底意图“其他意图”，且置信度仅 0.5，完全未能捕捉用户的核心业务目标，因此未满足任何业务期望。",
  "needs_human_review": true,
  "scenario": "intent_recognition",
  "quality_flags": ["intent_mismatch", "low_confidence", "potential_false_fallback"]
}

